registerApp({
  id: 'perf',
  name: 'Perf Monitor',
  icon: 'data:image/svg+xml;base64,',
  description: 'Live FPS, memory, DOM node count, and long task tracking',
  category: 'developer',
  devOnly: true,
  autoGrant: true,
  defaultSize: [600, 500],
  minSize: [400, 350],
  permissions: ['system:info', 'system:settings'],
  init(content, state, options) {
    if (!window.AppDirs?.getVFSDir('com.nbosp.settings', 'files')) {
      content.style.cssText = 'display:flex;align-items:center;justify-content:center;height:100%;flex-direction:column;gap:12px;font-family:var(--font-ui,sans-serif);color:var(--text-muted,#888);';
      content.innerHTML = '<div style="font-size:32px">⚠️</div><div style="font-size:14px;text-align:center"><b>com.nbosp.settings</b><br>App data directory missing.<br>This app requires NovaByte OS.</div>';
      return;
    }

    if (!OS.settings.get('devMode')) {
      content.style.cssText = 'display:flex;align-items:center;justify-content:center;height:100%;flex-direction:column;gap:12px;font-family:var(--font-ui,sans-serif);color:var(--text-muted,#888);';
      content.innerHTML = '<div style="font-size:32px">🔒</div><div style="font-size:14px;text-align:center">Enable Developer Mode in Settings to use Perf Monitor.</div>';
      return;
    }

    content.style.cssText = 'display:flex;flex-direction:column;height:100%;background:var(--bg-default,#0f1115);color:var(--text-primary,#e6e6e6);font-family:var(--font-ui,sans-serif);overflow:auto;padding:16px;font-size:13px;';

    const canvas = document.createElement('canvas');
    canvas.id = 'perf-chart';
    canvas.style.cssText = 'width:100%;height:200px;background:var(--bg-elevated);border-radius:6px;border:1px solid var(--border-subtle);';
    content.appendChild(canvas);

    const stats = createEl('div', { style: 'margin-top:12px;display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:8px;' });
    const addStat = (label, valueEl) => {
      const card = createEl('div', { style: 'padding:10px;background:var(--bg-elevated);border-radius:6px;border:1px solid var(--border-subtle);' });
      card.appendChild(createEl('div', { textContent: label, style: 'font-size:11px;color:var(--text-muted);margin-bottom:4px;' }));
      card.appendChild(valueEl);
      stats.appendChild(card);
    };

    const fpsEl = createEl('div', { textContent: '--', style: 'font-size:20px;font-weight:700;color:#3fb950;font-family:monospace;' });
    addStat('FPS', fpsEl);

    const memEl = createEl('div', { textContent: '--', style: 'font-size:13px;font-family:monospace;' });
    addStat('Memory', memEl);

    const domEl = createEl('div', { textContent: '--', style: 'font-size:13px;font-family:monospace;' });
    addStat('DOM Nodes', domEl);

    const longEl = createEl('div', { textContent: '--', style: 'font-size:13px;font-family:monospace;' });
    addStat('Long Tasks', longEl);

    content.appendChild(stats);

    // FPS history for sparkline
    const fpsHistory = new Array(120).fill(0);
    let lastFrameTime = performance.now();
    let frameCount = 0;
    let rafId = null;

    // Long task tracking via PerformanceObserver.
    // 'longtask' is deprecated in Chrome in favor of 'long-animation-frame'
    // (Long Animation Frames API). We observe whichever is supported and
    // count entries over the 500ms measurement window. The original code
    // polled performance.getEntriesByType('longtask') on a timer while only
    // checking `typeof PerformanceObserver !== 'undefined'` as a guard —
    // that check never actually used the observer, so it silently kept
    // working (for now) on the deprecated API. This version subscribes
    // properly and prefers the replacement entry type when available.
    let longTaskCount = 0;
    let longTaskSupported = false;
    let longTaskObserver = null;

    if (typeof PerformanceObserver !== 'undefined') {
      const supportedTypes = PerformanceObserver.supportedEntryTypes || [];
      const entryType = supportedTypes.includes('long-animation-frame')
        ? 'long-animation-frame'
        : (supportedTypes.includes('longtask') ? 'longtask' : null);

      if (entryType) {
        longTaskSupported = true;
        try {
          longTaskObserver = new PerformanceObserver((list) => {
            longTaskCount += list.getEntries().filter(e => e.duration > 50).length;
          });
          longTaskObserver.observe({ type: entryType, buffered: true });
        } catch {
          longTaskSupported = false;
        }
      }
    }

    function measureFrame() {
      const now = performance.now();
      frameCount++;
      if (now - lastFrameTime >= 500) {
        const fps = Math.round((frameCount * 1000) / (now - lastFrameTime));
        fpsHistory.push(fps);
        fpsHistory.shift();
        frameCount = 0;
        lastFrameTime = now;
        drawChart();
        updateStats();
      }
      rafId = requestAnimationFrame(measureFrame);
    }

    function drawChart() {
      const ctx = canvas.getContext('2d');
      const w = canvas.width = canvas.offsetWidth * 2;
      const h = canvas.height = canvas.offsetHeight * 2;
      ctx.scale(2, 2);
      const cw = w / 2, ch = h / 2;
      ctx.clearRect(0, 0, cw, ch);

      const max = Math.max(120, ...fpsHistory);
      const stepX = cw / (fpsHistory.length - 1);

      // 60fps reference line
      const y60 = ch - (60 / max) * ch;
      ctx.strokeStyle = 'rgba(0,255,0,0.2)';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(0, y60);
      ctx.lineTo(cw, y60);
      ctx.stroke();

      // FPS line
      ctx.strokeStyle = '#0f0';
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      fpsHistory.forEach((fps, i) => {
        const x = i * stepX;
        const y = ch - (fps / max) * ch;
        if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
      });
      ctx.stroke();

      // Fill under line
      ctx.lineTo(cw, ch);
      ctx.lineTo(0, ch);
      ctx.closePath();
      ctx.fillStyle = 'rgba(0,255,0,0.05)';
      ctx.fill();
    }

    function updateStats() {
      const latest = fpsHistory[fpsHistory.length - 1] || 0;
      fpsEl.textContent = latest + ' fps';

      if (performance.memory) {
        const mb = performance.memory.usedJSHeapSize / 1048576;
        memEl.textContent = mb.toFixed(1) + ' MB';
      } else {
        memEl.textContent = 'N/A';
      }

      domEl.textContent = String(document.querySelectorAll('*').length);

      if (longTaskSupported) {
        longEl.textContent = longTaskCount > 0 ? longTaskCount + ' (>50ms)' : 'None';
        longTaskCount = 0; // reset for next window; the observer accumulates continuously
      } else {
        longEl.textContent = 'N/A';
      }
    }

    rafId = requestAnimationFrame(measureFrame);

    // state.cleanups.push(fn) is the teardown hook the window manager
    // actually calls on close (confirmed against wm.js) — init()'s return
    // value is discarded and content never dispatches a 'close' event
    // anywhere in this codebase, so that listener would never have run and
    // both the rAF loop and the PerformanceObserver would leak for the life
    // of the OS session every time this window was closed.
    state.cleanups.push(() => {
      if (rafId) cancelAnimationFrame(rafId);
      if (longTaskObserver) longTaskObserver.disconnect();
    });
  }
});